import Foundation

enum NetworkError: Error {
    case invalidURL
    case noData
    case decodingError
    case unauthorized
}

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development: return "https://dev.api.example.com"
        case .staging: return "https://staging.api.example.com"
        case .production: return "https://api.example.com"
        }
    }
}

class NetworkManager {
    static let shared = NetworkManager()
    private let session: URLSession
    private let environment: Environment
    
    private init(environment: Environment = .production) {
        self.environment = environment
        let config = URLSessionConfiguration.default
        config.httpAdditionalHeaders = ["Content-Type": "application/json"]
        config.timeoutInterval = 30
        self.session = URLSession(configuration: config)
    }
    
    func fetchUserData(completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/user") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(TokenManager.shared.accessToken)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Network error: \(error)")
                completion(.failure(.noData))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let user = try JSONDecoder().decode(User.self, from: data)
                completion(.success(user))
            } catch {
                completion(.failure(.decodingError))
            }
        }
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/auth/login") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: ["username": username, "password": password])
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Network error: \(error)")
                completion(.failure(.noData))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let authResponse = try JSONDecoder().decode(AuthResponse.self, from: data)
                TokenManager.shared.accessToken = authResponse.accessToken
                completion(.success(authResponse))
            } catch {
                completion(.failure(.decodingError))
            }
        }
        task.resume()
    }
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct AuthResponse: Codable {
    let accessToken: String
    let expiresIn: Int
}

class TokenManager {
    static let shared = TokenManager()
    private let userDefaults = UserDefaults.standard
    private let tokenKey = "access_token"
    
    var accessToken: String {
        get {
            return userDefaults.string(forKey: tokenKey) ?? ""
        }
        set {
            userDefaults.set(newValue, forKey: tokenKey)
        }
    }
}